          ${entry.username},
          ${entry.level},
          ${entry.outcome},
          ${entry.completedGame},
          ${entry.score},
          ${entry.timeRemaining},
          ${entry.durationSeconds},
          ${entry.progressCompleted},
          ${entry.progressTotal},
          ${entry.mistakes},
