export default async function handler(req, res) {
  if (req.method === "OPTIONS") {
    res.statusCode = 204;
    res.end();
    return;
  }

  try {
    await ensureSchema();
    const sql = getSql();

    if (req.method === "GET") {
      const query = req.query || {};
      const typeParam = String(readQueryValue(query.type) || "").toLowerCase();
      const type = TYPES.has(typeParam) ? typeParam : "winners";
      const limit = readLimit(query.limit);
      const entries = await listEntries(sql, type, limit);
      sendJson(res, 200, { entries, source: "database" });
      return;
    }

    if (req.method === "POST") {
      const entry = validateEntry(readBody(req));
      const inserted = await sql`
        INSERT INTO leaderboard_entries (
          id,
          username,
          level,
          outcome,
          completed_game,
          score,
          time_remaining,
          duration_seconds,
          progress_completed,
          progress_total,
          mistakes,
          questions_completed
        )
        VALUES (
          ${entry.id},
          ${entry.username},
          ${entry.level},
          ${entry.outcome},
          ${entry.completedGame},
          ${entry.score},
          ${entry.timeRemaining},
          ${entry.durationSeconds},
          ${entry.progressCompleted},
          ${entry.progressTotal},
          ${entry.mistakes},
          ${entry.level === 3 ? entry.progressCompleted : 0}
        )
        RETURNING
          id,
          username,
          level,
          outcome,
          completed_game AS "completedGame",
          score,
          time_remaining AS "timeRemaining",
          duration_seconds AS "durationSeconds",
          progress_completed AS "progressCompleted",
          progress_total AS "progressTotal",
          mistakes,
          questions_completed AS "questionsCompleted",
          created_at AS "createdAt"
      `;
      const entries = await listEntries(sql, entry.completedGame ? "winners" : "attempts", DEFAULT_LIMIT);
      sendJson(res, 201, { entry: inserted[0], entries, source: "database" });
      return;
    }

    res.setHeader("Allow", "GET, POST, OPTIONS");
    sendJson(res, 405, { error: "Method not allowed" });
  } catch (error) {
    const status = error.statusCode || 500;
    const message = status === 500 ? "Leaderboard is unavailable" : error.message;
    console.error("leaderboard api error", error);
    sendJson(res, status, { error: message });
  }
}

