    return { entries: payload.entries.map(normalizeEntry), source: payload.source || "database" };
  } catch {
    return {
      entries: sortEntries(getLocalEntries(), type).slice(0, DISPLAY_LIMIT),
      source: import.meta.env?.DEV ? "dev-local" : "local",
