  grid-template-columns: 68px minmax(0, 1fr) 168px 68px minmax(0, 1fr) 168px;
  gap: 0 clamp(30px, 5vw, 78px);
  align-items: end;
  margin-bottom: 8px;
}
.lb-table-head span {
  color: #fff;
  font-size: clamp(22px, 2.9vw, 42px);
  font-weight: 950;
  text-transform: uppercase;
  -webkit-text-stroke: clamp(1.4px, 0.22vw, 3px) #02040a;
  paint-order: stroke fill;
  text-shadow: 0 4px 0 #02040a;
}
.lb-table-head span:nth-child(3),
.lb-table-head span:nth-child(6) {
  text-align: right;
}
.lb-list {
  display: grid;
  grid-auto-flow: column;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  grid-template-rows: repeat(5, minmax(44px, auto));
  gap: clamp(8px, 1.35vh, 16px) clamp(30px, 5vw, 78px);
  max-height: none;
  overflow: visible;
  list-style: none;
}
.lb-row {
  display: grid;
  grid-template-columns: 68px minmax(0, 1fr) 168px;
  align-items: center;
  min-height: clamp(38px, 5.4vh, 64px);
  color: #fff;
  font-size: clamp(24px, 3vw, 44px);
  font-weight: 950;
  font-variant-numeric: tabular-nums;
}
.lb-rank,
.lb-name,
.lb-points,
.lb-avatar,
.lb-back {
  -webkit-text-stroke: clamp(1.5px, 0.24vw, 3px) #02040a;
  paint-order: stroke fill;
  text-shadow:
    0 4px 0 #02040a,
    3px 0 0 #02040a,
    -3px 0 0 #02040a;
}
.lb-rank {
  color: #fff;
}
.lb-player {
  display: grid;
  grid-template-columns: clamp(34px, 4.4vw, 58px) minmax(0, 1fr);
  align-items: center;
  gap: clamp(10px, 1.4vw, 18px);
  min-width: 0;
}
.lb-avatar {
  display: inline-grid;
  place-items: center;
  width: clamp(34px, 4.4vw, 58px);
  aspect-ratio: 1;
  color: #11131e;
  background: #f6efe4;
  border: 3px solid #02040a;
  border-radius: 50%;
  box-shadow: 0 3px 0 #02040a;
  font-size: clamp(16px, 2vw, 28px);
}
.lb-row:nth-child(3n + 2) .lb-avatar { background: #ffd3c8; }
.lb-row:nth-child(3n + 3) .lb-avatar { background: #d7ffd0; }
.lb-name {
  min-width: 0;
  overflow: hidden;
  color: #fff;
  text-overflow: ellipsis;
  text-decoration: underline;
  text-decoration-color: #02040a;
  text-decoration-thickness: 4px;
  text-underline-offset: 6px;
  white-space: nowrap;
}
.lb-points {
  color: #fff;
  text-align: right;
}
.lb-empty {
  grid-column: 1 / -1;
  align-self: center;
  padding: 20px;
  color: #fff;
  font-size: clamp(22px, 3vw, 40px);
  font-weight: 950;
  text-align: center;
  -webkit-text-stroke: 2px #02040a;
  paint-order: stroke fill;
  text-shadow: 0 4px 0 #02040a;
}
.lb-back {
  display: block;
  margin: clamp(28px, 5.5vh, 62px) auto 0;
  padding: 4px 22px;
  color: #fff;
  background: transparent;
  border: 0;
  border-radius: 6px;
  font-family: inherit;
  font-size: clamp(34px, 4.5vw, 58px);
  font-weight: 950;
  cursor: pointer;
}
.lb-back:focus-visible {
  outline: 3px solid #fff;
  outline-offset: 7px;
}

@media (max-width: 760px) {
  #lc-ignition { font-size: 72px; }
  #lc-ignition.is-go { font-size: 38px; }
  .leaderboard {
    overflow-y: auto;
    padding: 26px 16px 20px;
  }
  .lb-title {
    font-size: clamp(34px, 11vw, 56px);
  }
  .lb-submit-row {
    grid-template-columns: 1fr;
  }
  .lb-board {
    width: 100%;
  }
  .lb-saved-row {
    grid-template-columns: minmax(0, 1fr) 92px;
  }
  .lb-saved-row .lb-result {
    display: none;
  }
  .lb-table-head {
    grid-template-columns: 40px minmax(0, 1fr) 104px;
    gap: 8px;
  }
  .lb-table-head span:nth-child(n + 4) {
    display: none;
  }
  .lb-list {
    grid-auto-flow: row;
    grid-template-columns: 1fr;
    grid-template-rows: none;
    gap: 8px;
  }
  .lb-row {
    grid-template-columns: 40px minmax(0, 1fr) 104px;
    min-height: 42px;
    font-size: clamp(21px, 6vw, 31px);
  }
  .lb-player {
    grid-template-columns: clamp(28px, 8vw, 38px) minmax(0, 1fr);
    gap: 8px;
  }
  .lb-avatar {
    width: clamp(28px, 8vw, 38px);
    border-width: 2px;
    font-size: clamp(13px, 4vw, 19px);
  }
}

