import fs from 'node:fs';
import { neon } from '@neondatabase/serverless';

const env = fs.readFileSync('.env.local', 'utf8');
for (const line of env.split(/\r?\n/)) {
  const trimmed = line.trim();
  if (!trimmed || trimmed.startsWith('#')) continue;
  const match = trimmed.match(/^([A-Za-z_][A-Za-z0-9_]*)=(.*)$/);
  if (!match) continue;
  const [, key, rawValue] = match;
  const value = rawValue.replace(/^['"]|['"]$/g, '');
  if (!(key in process.env)) process.env[key] = value;
}

const connectionString = process.env.DATABASE_URL || process.env.POSTGRES_URL;
if (!connectionString) throw new Error('No database URL found');
const sql = neon(connectionString);
const removed = await sql`
  DELETE FROM leaderboard_entries
  WHERE username IN ('OverlayTest', 'MobileTest')
  RETURNING username, score
`;
console.log(JSON.stringify({ removed: removed.length, usernames: removed.map((row) => row.username) }));
